<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Sorting Visualizer</title>
  <style>
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: #121218;
      color: #e0e6ed;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 20px;
    }

    h1 {
      margin-bottom: 20px;
      font-weight: 600;
      font-size: 1.8rem;
      color: #f3f4f6;
    }

    .controls {
      display: flex;
      gap: 12px;
      margin-bottom: 24px;
    }

    button {
      background-color: #2a2b36;
      color: #e0e6ed;
      border: 1px solid #3f4156;
      padding: 10px 20px;
      font-size: 0.95rem;
      font-weight: 500;
      border-radius: 6px;
      cursor: pointer;
      transition: background-color 0.2s ease, transform 0.1s ease;
    }

    button:hover {
      background-color: #3b3d52;
    }

    button:active {
      transform: scale(0.98);
    }

    #bars {
      display: flex;
      align-items: flex-end;
      justify-content: center;
      gap: 4px;
      width: 100%;
      max-width: 800px;
      height: 380px;
      background-color: #1a1b26;
      border: 1px solid #2f334d;
      border-radius: 8px;
      padding: 20px;
      box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
    }

    .bar {
      flex: 1;
      background-color: #7aa2f7;
      border-radius: 3px 3px 0 0;
      transition: height 0.08s ease, background-color 0.08s ease;
      min-width: 2px;
    }

    .bar.active {
      background-color: #f7768e;
    }

    .bar.sorted {
      background-color: #9ece6a;
    }
  </style>
</head>
<body>

  <h1>Sorting Visualizer</h1>

  <div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>

  <div id="bars"></div>

  <script>
    let currentArray = [];
    let savedArray = [];
    let sortGen = null;
    let animId = null;

    function isSorted(arr) {
      for (let i = 0; i < arr.length - 1; i++) {
        if (arr[i] > arr[i + 1]) return false;
      }
      return true;
    }

    function* bubbleSortGen(arr) {
      while (!isSorted(arr)) {
        for (let i = 0; i < arr.length - 1; i++) {
          if (arr[i] > arr[i + 1]) {
            let temp = arr[i];
            arr[i] = arr[i + 1];
            arr[i + 1] = temp;
          }
          yield { active: [i, i + 1] };
          if (isSorted(arr)) break;
        }
      }
    }

    function stopAnimation() {
      if (animId !== null) {
        clearInterval(animId);
        animId = null;
      }
    }

    function sorted() {
      return isSorted(currentArray);
    }

    function setArray(a) {
      stopAnimation();
      currentArray = Array.from(a, Number);
      savedArray = [...currentArray];
      sortGen = bubbleSortGen(currentArray);
      redraw();
    }

    function sortStep() {
      if (sorted()) {
        redraw();
        return true;
      }
      if (!sortGen) {
        sortGen = bubbleSortGen(currentArray);
      }
      const res = sortGen.next();
      const activeIndices = (res.value && res.value.active) ? res.value.active : [];
      const done = sorted();
      redraw(activeIndices);
      return done;
    }

    function redraw(activeIndices = []) {
      const container = document.getElementById('bars');
      if (!container) return;
      container.innerHTML = '';

      if (currentArray.length === 0) return;

      const maxVal = Math.max(...currentArray, 1);
      const minVal = Math.min(...currentArray, 0);
      const range = maxVal - minVal || 1;
      const allSorted = sorted();

      currentArray.forEach((val, idx) => {
        const bar = document.createElement('div');
        bar.className = 'bar';

        let heightPercent;
        if (minVal >= 0) {
          heightPercent = maxVal > 0 ? (val / maxVal) * 90 + 10 : 10;
        } else {
          heightPercent = ((val - minVal) / range) * 90 + 10;
        }

        bar.style.height = `${heightPercent}%`;

        if (allSorted) {
          bar.classList.add('sorted');
        } else if (activeIndices.includes(idx)) {
          bar.classList.add('active');
        }

        bar.title = String(val);
        container.appendChild(bar);
      });
    }

    function generateRandomArray(size = 20) {
      const arr = [];
      for (let i = 0; i < size; i++) {
        arr.push(Math.floor(Math.random() * 90) + 10);
      }
      return arr;
    }

    function startSortAnimation() {
      stopAnimation();
      if (sorted()) return;
      animId = setInterval(() => {
        const done = sortStep();
        if (done) {
          stopAnimation();
        }
      }, 40);
    }

    document.getElementById('sort').addEventListener('click', () => {
      startSortAnimation();
    });

    document.getElementById('shuffle').addEventListener('click', () => {
      setArray(generateRandomArray(20));
    });

    document.getElementById('reset').addEventListener('click', () => {
      setArray([...savedArray]);
    });

    window.viz = {
      array: () => [...currentArray],
      setArray: (a) => setArray(a),
      sortStep: () => sortStep(),
      sorted: () => sorted()
    };

    setArray(generateRandomArray(20));
  </script>
</body>
</html>
